  var cwd = opts.cwd;
  var send = opts.send;
  var sendTo = opts.sendTo;

  var nextId = 1;
  var terminals = new Map(); // id -> terminal session

  function create(cols, rows) {
    if (terminals.size >= MAX_TERMINALS) return null;

    var pty = createTerminal(cwd, cols, rows);
    if (!pty) return null;

    var id = nextId++;
    var session = {
      id,
      pty,
      scrollback: "",
      scrollbackSize: 0,
      cols,
      rows,
      listeners: new Set(),
    };

    terminals.set(id, session);

    pty.on("data", function (data) {
      session.scrollback += data;
      session.scrollbackSize += data.length;
      if (session.scrollbackSize > SCROLLBACK_MAX) {
        // trim oldest data
        var excess = session.scrollbackSize - SCROLLBACK_MAX;
        session.scrollback = session.scrollback.slice(excess);
        session.scrollbackSize = SCROLLBACK_MAX;
      }
      for (var listener of session.listeners) {
        listener(data);
      }
      sendTo(id, data);
    });

    return id;
